import React, { useState, useEffect, useRef } from 'react';
import axios from 'axios';

function App() {
  const [etapa, setEtapa] = useState('login'); 
  const [modo, setModo] = useState(''); 
  const [codigo, setCodigo] = useState("");
  const [usuario, setUsuario] = useState(null);
  const [mensagem, setMensagem] = useState("Aguardando crachá...");
  const [processando, setProcessando] = useState(false);
  const inputRef = useRef(null);

  useEffect(() => {
    inputRef.current?.focus();
  }, [etapa, modo]);

  // FUNÇÃO ATUALIZADA E BLINDADA
  const handleKeyPress = async (e) => {
    if (e.key === 'Enter') {
      e.preventDefault(); // Impede o navegador de dar refresh
      e.stopPropagation(); // Impede que o evento suba para outros elementos

      const valorLido = codigo.trim();

      // Bloqueio de segurança: se estiver processando ou o código for vazio, não faz nada
      if (!valorLido || processando) {
        return;
      }

      setProcessando(true); // Ativa a trava
      console.log("Código lido pelo scanner:", valorLido);

      try {
        if (etapa === 'login') {
          await realizarLogin(valorLido);
        } else if (etapa === 'acao') {
          await processarAcao(valorLido);
        }
      } catch (error) {
        console.error("Erro na leitura:", error);
        setMensagem("❌ Erro de comunicação.");
      } finally {
        // Limpa o campo e libera a trava após um pequeno delay para o leitor "esfriar"
        setCodigo("");
        setTimeout(() => {
          setProcessando(false);
          inputRef.current?.focus();
        }, 500); 
      }
    }
  };

  const realizarLogin = async (codBarras) => {
    try {
      const res = await axios.post('http://localhost:3001/login', { codBarras });
      setUsuario(res.data);
      setEtapa('escolha');
      setMensagem(`Olá, ${res.data.nome}! Escolha a opção:`);
    } catch (err) {
      setMensagem("❌ Usuário não cadastrado.");
    }
  };

  const processarAcao = async (ferramentacod) => {
    const url = modo === 'retirada' ? '/emprestimo/retirada' : '/emprestimo/devolucao';
    const dados = modo === 'retirada' 
      ? { usuarioId: usuario.id, ferramentacod } 
      : { ferramentacod };

    try {
      const res = await axios.post(`http://localhost:3001${url}`, dados);
      setMensagem(`✅ ${res.data}`);
      setTimeout(() => {
        setEtapa('login');
        setUsuario(null);
        setModo('');
        setMensagem("Aguardando crachá...");
      }, 3000);
    } catch (err) {
      setMensagem("❌ Ferramenta inválida ou já em uso.");
    }
  };

  return (
    <div style={styles.container}>
      <header style={styles.header}>
        <img src="/logo-tsea.png" style={styles.logo} alt="logo" />
        <h1 style={styles.title}>TSEA - Rastreabilidade</h1>
      </header>
      
      <div style={styles.card}>
        <h2 style={{ color: processando ? '#999' : '#002d62' }}>{mensagem}</h2>

        {etapa === 'escolha' && (
          <div style={styles.btnContainer}>
            <button 
              onClick={() => { setModo('retirada'); setEtapa('acao'); setMensagem("Bipe a FERRAMENTA (Retirada)"); }} 
              style={{...styles.button, backgroundColor: '#0055ff'}}
            >
              PEGAR FERRAMENTA
            </button>
            <button 
              onClick={() => { setModo('devolucao'); setEtapa('acao'); setMensagem("Bipe a FERRAMENTA (Entrega)"); }} 
              style={{...styles.button, backgroundColor: '#28a745'}}
            >
              ENTREGAR FERRAMENTA
            </button>
          </div>
        )}

        {(etapa === 'login' || etapa === 'acao') && (
          <input 
            ref={inputRef}
            value={codigo} 
            onChange={(e) => setCodigo(e.target.value)} 
            onKeyDown={handleKeyPress} 
            placeholder="Aguardando scanner..." 
            style={{...styles.input, borderColor: processando ? '#ccc' : '#0055ff'}}
            disabled={processando}
            autoComplete="off"
          />
        )}
      </div>
    </div>
  );
}

const styles = {
  container: { textAlign: 'center', marginTop: '50px', fontFamily: 'Arial' },
  header: { marginBottom: '20px' },
  logo: { width: '180px' },
  title: { color: '#002d62' },
  card: { padding: '30px', border: '1px solid #ddd', display: 'inline-block', borderRadius: '15px', backgroundColor: '#fff' },
  input: { padding: '15px', fontSize: '20px', width: '300px', border: '2px solid', textAlign: 'center', borderRadius: '8px' },
  button: { padding: '15px', fontSize: '16px', color: 'white', border: 'none', borderRadius: '8px', margin: '10px', cursor: 'pointer', width: '200px' },
  btnContainer: { display: 'flex', flexDirection: 'column', alignItems: 'center' }
};

export default App;
